export type Value = string | number | boolean | null | undefined | Value[] | {
    [k: string]: Value;
};
export type TemplateData = {
    [k: string]: Value;
};
export type Template<T = TemplateData> = (data: T) => string;
export type CustomFn = (...args: Value[]) => Value;
export declare const compile: <T = TemplateData>(tmpl: string) => Template<T>;
export declare const render: <T = TemplateData>(tmpl: string, data: T) => string;
export declare const registerFunction: (name: string, fn: CustomFn) => void;
